const payload = items[0]?.json ?? {};
const body = payload.body && typeof payload.body === 'object' ? payload.body : payload;

const required = ['incident_id', 'service', 'severity', 'summary'];
const missing = required.filter(field => body[field] === undefined || body[field] === null || String(body[field]).trim() === '');
if (missing.length) {
  throw new Error(`Missing required incident fields: ${missing.join(', ')}`);
}

const severity = String(body.severity).trim().toUpperCase();
const processSeverity = ['SEV1', 'SEV2'].includes(severity);
let simulateFailures = {};
try {
  simulateFailures = typeof body.simulate_failures === 'string'
    ? JSON.parse(body.simulate_failures || '{}')
    : (body.simulate_failures ?? {});
} catch (error) {
  throw new Error('simulate_failures must be valid JSON');
}

const normalised = {
  incident_id: String(body.incident_id).trim(),
  service: String(body.service).trim(),
  severity,
  summary: String(body.summary).trim(),
  url: body.url || body.alert_url || '',
  environment: body.environment || 'production',
  received_at: new Date().toISOString(),
  process_incident: processSeverity,
  ignored_reason: processSeverity ? null : 'Only SEV1/SEV2 incidents are orchestrated by this workflow',
  simulate_failures: simulateFailures,
};

return [{ json: normalised }];

const incident = items[0]?.json ?? {};
const runAt = new Date().toISOString();
const base = `${incident.incident_id}:${incident.service}:${incident.severity}`;
const actions = ['collaboration', 'ticketing', 'status_page', 'on_call', 'incident_record'];
const idempotencyKeys = Object.fromEntries(actions.map(action => [action, `${base}:${action}`]));

const serviceMap = {
  'payments-api': { team: 'payments-platform', on_call: 'alice@yourcompany.com', ticket_prefix: 'PAY', status_component: 'Payments API' },
  'auth-api': { team: 'identity-platform', on_call: 'identity-oncall@yourcompany.com', ticket_prefix: 'AUTH', status_component: 'Authentication' },
  'web-app': { team: 'web-platform', on_call: 'web-oncall@yourcompany.com', ticket_prefix: 'WEB', status_component: 'Web Application' },
};

const owner = serviceMap[incident.service] ?? {
  team: 'platform-operations',
  on_call: 'platform-oncall@yourcompany.com',
  ticket_prefix: 'OPS',
  status_component: incident.service,
};

return [{
  json: {
    ...incident,
    owner,
    control: {
      generated_at: runAt,
      idempotency_keys: idempotencyKeys,
      retry_policy: {
        max_attempts: 3,
        backoff: 'exponential',
        retry_on: ['429', '408', '5xx', 'network_timeout'],
        notes: 'Apply this policy to real alerting, Slack/Teams, ticketing, status page and incident-store connector nodes.'
      },
      severity_policy: {
        orchestrate: ['SEV1', 'SEV2'],
        sev1_public_status_page: true,
        sev2_internal_status_page_default: true,
      }
    },
    enrichment_results: {},
    action_results: {},
  },
}];

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
try {
  if (incident.simulate_failures?.deploys) throw new Error('Simulated deploy history source failure');
  const deploys = [
    { id: 'deploy_8821', service: incident.service, version: '2025.04.18.3', deployed_at: '2025-04-18T09:41:00Z', actor: 'ci@yourcompany.com' },
    { id: 'deploy_8819', service: incident.service, version: '2025.04.18.1', deployed_at: '2025-04-18T07:15:00Z', actor: 'ci@yourcompany.com' },
  ];
  return [{ json: { ...incident, recent_deploys_result: { source: 'deploys', status: 'success', checked_at: startedAt, completed_at: new Date().toISOString(), count: deploys.length, deploys } } }];
} catch (error) {
  return [{ json: { ...incident, recent_deploys_result: { source: 'deploys', status: 'failed', checked_at: startedAt, completed_at: new Date().toISOString(), error: error.message, deploys: [] } } }];
}

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
try {
  if (incident.simulate_failures?.related_tickets) throw new Error('Simulated related ticket source failure');
  const tickets = [
    { id: 'SUP-7712', title: 'Checkout timeout reports', status: 'open', priority: 'high' },
    { id: 'BUG-2219', title: 'Payments latency regression investigation', status: 'in_progress', priority: 'critical' },
  ];
  return [{ json: { ...incident, related_tickets_result: { source: 'related_tickets', status: 'success', checked_at: startedAt, completed_at: new Date().toISOString(), count: tickets.length, tickets } } }];
} catch (error) {
  return [{ json: { ...incident, related_tickets_result: { source: 'related_tickets', status: 'failed', checked_at: startedAt, completed_at: new Date().toISOString(), error: error.message, tickets: [] } } }];
}

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
try {
  if (incident.simulate_failures?.on_call_lookup) throw new Error('Simulated on-call lookup failure');
  const onCall = {
    email: incident.owner?.on_call || 'platform-oncall@yourcompany.com',
    escalation_policy: `${incident.owner?.team || 'platform'}-primary`,
    source: 'static_service_map_demo',
  };
  return [{ json: { ...incident, on_call_result: { source: 'on_call', status: 'success', checked_at: startedAt, completed_at: new Date().toISOString(), on_call: onCall } } }];
} catch (error) {
  return [{ json: { ...incident, on_call_result: { source: 'on_call', status: 'failed', checked_at: startedAt, completed_at: new Date().toISOString(), error: error.message, on_call: null } } }];
}

const source = items[0]?.json ?? {};
const enrichment = {
  deploys: source.recent_deploys_result,
  related_tickets: source.related_tickets_result,
  on_call: source.on_call_result,
};

const warnings = Object.values(enrichment)
  .filter(result => result && result.status !== 'success')
  .map(result => `${result.source}: ${result.status}${result.error ? ` (${result.error})` : ''}`);

return [{
  json: {
    ...source,
    enrichment_results: enrichment,
    enrichment_warnings: warnings,
  },
}];

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
const action = 'collaboration';
try {
  if (incident.simulate_failures?.collaboration) throw new Error('Simulated Slack/Teams channel creation failure');
  const channelName = `#inc-${incident.severity.toLowerCase()}-${incident.incident_id}`.replace(/[^#a-z0-9_-]/gi, '-').toLowerCase();
  const result = {
    action,
    status: 'success',
    idempotency_key: incident.control.idempotency_keys.collaboration,
    started_at: startedAt,
    completed_at: new Date().toISOString(),
    channel_name: channelName,
    channel_url: `https://your-slack-workspace.slack.com/archives/${channelName.replace('#','')}`,
    invited: [incident.enrichment_results?.on_call?.on_call?.email || incident.owner.on_call, 'incident-commander@yourcompany.com'],
  };
  return [{ json: { ...incident, collaboration_action_result: result } }];
} catch (error) {
  return [{ json: { ...incident, collaboration_action_result: { action, status: 'failed', idempotency_key: incident.control?.idempotency_keys?.collaboration, started_at: startedAt, completed_at: new Date().toISOString(), error: error.message } } }];
}

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
const action = 'ticketing';
try {
  if (incident.simulate_failures?.ticketing) throw new Error('Simulated Jira/Linear ticket failure');
  const prefix = incident.owner?.ticket_prefix || 'OPS';
  const numeric = Math.abs([...incident.incident_id].reduce((sum, ch) => sum + ch.charCodeAt(0), 0)) % 9000 + 1000;
  const ticketId = `${prefix}-${numeric}`;
  const result = {
    action,
    status: 'success',
    idempotency_key: incident.control.idempotency_keys.ticketing,
    started_at: startedAt,
    completed_at: new Date().toISOString(),
    ticket_id: ticketId,
    ticket_url: `https://your-jira-instance/browse/${ticketId}`,
  };
  return [{ json: { ...incident, ticketing_action_result: result } }];
} catch (error) {
  return [{ json: { ...incident, ticketing_action_result: { action, status: 'failed', idempotency_key: incident.control?.idempotency_keys?.ticketing, started_at: startedAt, completed_at: new Date().toISOString(), error: error.message } } }];
}

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
const action = 'status_page';
try {
  if (incident.simulate_failures?.status_page) throw new Error('Simulated status page API failure');
  const shouldPublish = incident.severity === 'SEV1' || incident.control?.severity_policy?.sev2_internal_status_page_default;
  if (!shouldPublish) {
    return [{ json: { ...incident, status_page_action_result: { action, status: 'skipped', reason: 'Status page update not required by policy', started_at: startedAt, completed_at: new Date().toISOString() } } }];
  }
  const statusPageId = `sp_${incident.incident_id}`;
  const result = {
    action,
    status: 'success',
    idempotency_key: incident.control.idempotency_keys.status_page,
    started_at: startedAt,
    completed_at: new Date().toISOString(),
    status_page_id: statusPageId,
    status_page_url: `https://status.yourcompany.com/incidents/${statusPageId}`,
    audience: incident.severity === 'SEV1' ? 'public_or_customer_visible_by_policy' : 'internal',
  };
  return [{ json: { ...incident, status_page_action_result: result } }];
} catch (error) {
  return [{ json: { ...incident, status_page_action_result: { action, status: 'failed', idempotency_key: incident.control?.idempotency_keys?.status_page, started_at: startedAt, completed_at: new Date().toISOString(), error: error.message } } }];
}

const incident = { ...items[0].json };
const startedAt = new Date().toISOString();
const action = 'on_call';
try {
  if (incident.simulate_failures?.on_call_notify) throw new Error('Simulated on-call notification failure');
  const onCall = incident.enrichment_results?.on_call?.on_call?.email || incident.owner?.on_call || 'platform-oncall@yourcompany.com';
  const result = {
    action,
    status: 'success',
    idempotency_key: incident.control.idempotency_keys.on_call,
    started_at: startedAt,
    completed_at: new Date().toISOString(),
    notified: onCall,
    notification_channel: 'pager_or_dm_placeholder',
  };
  return [{ json: { ...incident, on_call_action_result: result } }];
} catch (error) {
  return [{ json: { ...incident, on_call_action_result: { action, status: 'failed', idempotency_key: incident.control?.idempotency_keys?.on_call, started_at: startedAt, completed_at: new Date().toISOString(), error: error.message } } }];
}

const source = items[0]?.json ?? {};
const actions = {
  collaboration: source.collaboration_action_result,
  ticketing: source.ticketing_action_result,
  status_page: source.status_page_action_result,
  on_call: source.on_call_action_result,
};
const actionValues = Object.values(actions).filter(Boolean);
const failed = actionValues.filter(a => a.status === 'failed');
const succeeded = actionValues.filter(a => a.status === 'success');
const skipped = actionValues.filter(a => a.status === 'skipped');

const orchestration_status = failed.length
  ? (succeeded.length ? 'partial_success' : 'failed')
  : 'success';

const liveIncident = {
  incident_id: source.incident_id,
  service: source.service,
  severity: source.severity,
  summary: source.summary,
  environment: source.environment,
  owner_team: source.owner?.team,
  on_call_engineer: source.on_call_action_result?.notified || source.enrichment_results?.on_call?.on_call?.email || source.owner?.on_call,
  orchestration_status,
  slack_channel: source.collaboration_action_result?.channel_name,
  ticket_id: source.ticketing_action_result?.ticket_id,
  status_page_id: source.status_page_action_result?.status_page_id,
  links: {
    alert: source.url,
    collaboration: source.collaboration_action_result?.channel_url,
    ticket: source.ticketing_action_result?.ticket_url,
    status_page: source.status_page_action_result?.status_page_url,
  },
  enrichment_warnings: source.enrichment_warnings || [],
  failed_actions: failed.map(a => ({ action: a.action, error: a.error })),
};

return [{
  json: {
    ...source,
    action_results: actions,
    orchestration_status,
    live_incident: liveIncident,
  },
}];

const source = items[0]?.json ?? {};
const failedActions = Object.values(source.action_results ?? {}).filter(action => action?.status === 'failed');
const failedEnrichment = Object.values(source.enrichment_results ?? {}).filter(result => result?.status && result.status !== 'success');
const alerts = [];
for (const action of failedActions) {
  alerts.push({
    alert_type: 'incident_orchestration_action_failure',
    severity: source.severity,
    incident_id: source.incident_id,
    action: action.action,
    error: action.error,
    recommended_action: 'Check the connector/API credentials, rate limits, destination availability and idempotency record before retrying.',
  });
}
for (const result of failedEnrichment) {
  alerts.push({
    alert_type: 'incident_enrichment_source_warning',
    severity: source.severity,
    incident_id: source.incident_id,
    source: result.source,
    status: result.status,
    error: result.error || null,
    recommended_action: 'Review whether the missing enrichment affects incident response decisions.',
  });
}
return [{ json: { ...source, operations_alerts: alerts } }];

const source = items[0]?.json ?? {};
const inc = source.live_incident;
const lines = [];
lines.push(`# ${inc.severity} Incident: ${inc.service}`);
lines.push('');
lines.push(`Incident ID: ${inc.incident_id}`);
lines.push(`Summary: ${inc.summary}`);
lines.push(`Owner team: ${inc.owner_team}`);
lines.push(`On-call: ${inc.on_call_engineer}`);
lines.push(`Orchestration status: ${inc.orchestration_status}`);
lines.push('');
lines.push('## Links');
for (const [label, url] of Object.entries(inc.links || {})) {
  if (url) lines.push(`- ${label}: ${url}`);
}
if (inc.enrichment_warnings?.length) {
  lines.push('');
  lines.push('## Enrichment warnings');
  for (const warning of inc.enrichment_warnings) lines.push(`- ${warning}`);
}
if (inc.failed_actions?.length) {
  lines.push('');
  lines.push('## Failed orchestration actions');
  for (const failure of inc.failed_actions) lines.push(`- ${failure.action}: ${failure.error}`);
}
lines.push('');
lines.push('## Immediate next steps');
lines.push('- Confirm incident commander and technical lead.');
lines.push('- Confirm customer impact and mitigation plan.');
lines.push('- Post first update according to communication policy.');

return [{
  json: {
    ...source,
    incident_channel_update_markdown: lines.join('\n'),
    notification_status: 'prepared_demo_payload_replace_with_slack_teams_or_email',
  },
}];

const source = items[0]?.json ?? {};
const inc = source.live_incident ?? {};
const timeline = [
  { time: source.received_at, event: 'Incident alert received' },
  { time: source.control?.generated_at, event: 'Incident orchestration started' },
  { time: new Date().toISOString(), event: 'Live incident object assembled' },
];

const prompt = `
You are drafting a post-incident review starting point for an engineering leadership team.

Use only the incident facts below. Do not invent root cause, customer impact, financial impact, or corrective actions. Mark unknowns explicitly.

Incident:
${JSON.stringify(inc, null, 2)}

Timeline:
${JSON.stringify(timeline, null, 2)}

Related deploys:
${JSON.stringify(source.enrichment_results?.deploys?.deploys || [], null, 2)}

Related tickets:
${JSON.stringify(source.enrichment_results?.related_tickets?.tickets || [], null, 2)}

Return a Markdown post-incident review draft with sections: Summary, Impact, Timeline, Detection, Response, Known Unknowns, Follow-up Actions.
`.trim();

return [{
  json: {
    ...source,
    post_incident_review: {
      status: 'prompt_prepared_optional_llm_step_not_executed_in_live_response_path',
      data_policy: 'Use after the incident is stable or resolved. Keep deterministic incident records as the authority.',
      prompt,
      timeline,
    },
  },
}];
